noncompliant:
public struct Money
{
    public static Money operator +(Money left, Money right) // Noncompliant: no Add method
    {
        return new Money(left.Amount + right.Amount);
    }
}

compliant:
public struct Money
{
    public static Money operator +(Money left, Money right)
    {
        return Add(left, right);
    }

    public static Money Add(Money left, Money right) // Named alternative
    {
        return new Money(left.Amount + right.Amount);
    }
}
